 */
const getPoolKeys = (): string[] => {
  const raw = process.env.API_KEY || "";
  const parts = raw.split(/[\s,;|\n\r]+/);
  const cleanedKeys = parts
    .map(k => k.trim()
      .replace(/['"“”]/g, '') 
      .replace(/[\u200B-\u200D\uFEFF]/g, '')
    )
    .filter(k => k.length >= 30);
  return [...new Set(cleanedKeys)];
};

