export const updateUserMemory = async (email: string, memoryUpdate: string) => {
  if (!db || !email) return;
  const emailLower = email.toLowerCase();
  const userRef = doc(doc(db, 'users', emailLower), 'private', 'memory'); 
  const snap = await getDoc(userRef);
  let existingMemory = "";
  if (snap.exists()) {
