  const isAdmin = userProfile ? db.isAdmin(userProfile.email) : false;
  const isUserDebi = userProfile?.email.toLowerCase().trim() === 'nitebiswaskotha@gmail.com';
  const isPro = userProfile?.subscriptionStatus === 'pro' || isAdmin;

